  1→import { useState } from 'react';
  2→import { useProject } from '@/app/ProjectProvider';
  3→import { useEditor } from '@/app/EditorProvider';
  4→import { getBeamDisplayLabel } from '@/domain/beamLabels';
  5→import { getColumnListLabel } from '@/domain/columnLabels';
  6→import { createFloorAboveHighest, getFloorElevation, getFloorLevelIndex, getOrderedFloors } from '@/domain/floorModels';
  7→import { createSheet, getSheetDisplayLabel } from '@/domain/sheetModels';
  8→import { getSlabDisplayLabel } from '@/domain/slabLabels';
  9→import { getStairDisplayLabel } from '@/domain/stairLabels';
 10→import { getLandingDisplayLabel } from '@/domain/landingLabels';
 11→import { getAnnotationDisplayLabel } from '@/annotations/format';
 12→import styles from './Sidebar.module.css';
 13→
 14→function Section({ title, count, collapsed, onToggle, collapsible = true, children }) {
 15→  return (
 16→    <div className={styles.section}>
 17→      <button
 18→        type="button"
 19→        className={`${styles.sectionHeader} ${collapsible ? styles.sectionHeaderClickable : ''}`}
 20→        onClick={collapsible ? onToggle : undefined}
 21→        aria-expanded={!collapsed}
 22→      >
 23→        <span className={`${styles.chevron} ${collapsed ? styles.chevronCollapsed : ''}`}>
 24→          {collapsible ? '▾' : ''}
 25→        </span>
 26→        <span className={styles.sectionTitle}>{title}</span>
 27→        {count !== undefined && <span className={styles.count}>{count}</span>}
 28→      </button>
 29→      {!collapsed && children}
 30→    </div>
 31→  );
 32→}
 33→
 34→export default function Sidebar() {
 35→  const { project, dispatch, duplicateFloor } = useProject();
 36→  const { activeFloorId, activeSheetId, selectedId, workspaceMode, dispatch: editorDispatch } = useEditor();
 37→  const orderedFloors = getOrderedFloors(project);
 38→  const floor = orderedFloors.find((entry) => entry.id === activeFloorId) || null;
 39→  const [collapsedSections, setCollapsedSections] = useState({
 40→    floors: false,
 41→    sheets: false,
 42→    slabs: false,
 43→    walls: false,
 44→    annotations: false,
 45→    beams: false,
 46→    stairs: false,
 47→    landings: false,
 48→    doors: false,
 49→    windows: false,
 50→    columns: false,
 51→    rooms: false,
 52→  });
 53→
 54→  const selectObject = (id, type) => {
 55→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
 56→  };
 57→
 58→  const selectFloor = (floorId) => {
 59→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 60→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
 61→    editorDispatch({ type: 'SELECT_OBJECT', id: floorId, objectType: 'floor' });
 62→  };
 63→
 64→  const setActiveFloor = (floorId) => {
 65→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
 66→  };
 67→
 68→  const addFloor = () => {
 69→    const nextFloor = createFloorAboveHighest(project.floors || []);
 70→    dispatch({ type: 'FLOOR_ADD', floor: nextFloor });
 71→    selectFloor(nextFloor.id);
 72→  };
 73→
 74→  const handleDuplicateFloor = (floorToDuplicate) => {
 75→    const duplicatedFloor = duplicateFloor(floorToDuplicate.id);
 76→    if (!duplicatedFloor) return;
 77→
 78→    dispatch({ type: 'FLOOR_DUPLICATE', floor: duplicatedFloor });
 79→    selectFloor(duplicatedFloor.id);
 80→  };
 81→
 82→  const handleDeleteFloor = (floorToDelete) => {
 83→    if ((project.floors || []).length <= 1) return;
 84→
 85→    const confirmed = window.confirm(`Delete "${floorToDelete.name}"?`);
 86→    if (!confirmed) return;
 87→
 88→    const remainingFloors = orderedFloors.filter((entry) => entry.id !== floorToDelete.id);
 89→    const fallbackFloor = remainingFloors[0] || null;
 90→
 91→    dispatch({
 92→      type: 'FLOOR_DELETE',
 93→      floorId: floorToDelete.id,
 94→      fallbackFloorId: fallbackFloor?.id ?? null,
 95→    });
 96→
 97→    if (floorToDelete.id === activeFloorId && fallbackFloor) {
 98→      if (workspaceMode === 'model') {
 99→        selectFloor(fallbackFloor.id);
100→      } else {
101→        setActiveFloor(fallbackFloor.id);
102→      }
103→    }
104→  };
105→
106→  const addSheet = () => {
107→    const nextIndex = (project.sheets || []).length + 1;
108→    const sheet = createSheet(`Sheet ${nextIndex}`, {
109→      drawingName: `Drawing ${nextIndex}`,
110→    });
111→    dispatch({ type: 'SHEET_ADD', sheet });
112→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
113→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
114→    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
115→  };
116→
117→  const toggleSection = (sectionKey) => {
118→    setCollapsedSections(current => ({
119→      ...current,
120→      [sectionKey]: !current[sectionKey],
121→    }));
122→  };
123→
124→  return (
125→    <div className={styles.sidebar}>
126→      <Section title="Project" collapsible={false}>
127→        <input
128→          className={styles.projectName}
129→          value={project.name}
130→          onChange={(e) => dispatch({ type: 'PROJECT_SET_NAME', name: e.target.value })}
131→        />
132→      </Section>
133→
134→      <Section
135→        title="Floors"
136→        count={orderedFloors.length}
137→        collapsed={collapsedSections.floors}
138→        onToggle={() => toggleSection('floors')}
139→      >
140→        <button type="button" className={styles.item} onClick={addFloor}>
141→          + Add Floor
142→        </button>
143→        {orderedFloors.map((entry) => (
144→          <div key={entry.id} className={styles.floorRow}>
145→            <button
146→              type="button"
147→              className={`${styles.item} ${entry.id === activeFloorId ? styles.itemSelected : ''} ${styles.floorButton}`}
148→              onClick={() => selectFloor(entry.id)}
149→            >
150→              <span className={styles.floorName}>{entry.name}</span>
151→              <span className={styles.floorMeta}>
152→                L{getFloorLevelIndex(entry)} · {Math.round(getFloorElevation(entry))} mm
153→              </span>
154→            </button>
155→            <div className={styles.floorActions}>
156→              <button
157→                type="button"
158→                className={styles.floorActionBtn}
159→                onClick={() => handleDuplicateFloor(entry)}
160→                title={`Duplicate ${entry.name}`}
161→              >
162→                Dup
163→              </button>
164→              <button
165→                type="button"
166→                className={`${styles.floorActionBtn} ${styles.floorActionDanger}`}
167→                onClick={() => handleDeleteFloor(entry)}
168→                title={`Delete ${entry.name}`}
169→                disabled={orderedFloors.length <= 1}
170→              >
171→                Del
172→              </button>
173→            </div>
174→          </div>
175→        ))}
176→      </Section>
177→
178→      <Section
179→        title="Sheets"
180→        count={(project.sheets || []).length}
181→        collapsed={collapsedSections.sheets}
182→        onToggle={() => toggleSection('sheets')}
183→      >
184→        <button type="button" className={styles.item} onClick={addSheet}>
185→          + Add Sheet
186→        </button>
187→        {(project.sheets || []).map((sheet, index) => (
188→          <div
189→            key={sheet.id}
190→            className={`${styles.item} ${workspaceMode === 'sheet' && activeSheetId === sheet.id ? styles.itemSelected : ''}`}
191→            onClick={() => {
192→              editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
193→              editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
194→              editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
195→            }}
196→          >
197→            {getSheetDisplayLabel(sheet, index)}
198→          </div>
199→        ))}
200→      </Section>
201→
202→      {floor && (
203→        <>
204→          <Section
205→            title="Slabs"
206→            count={(floor.slabs || []).length}
207→            collapsed={collapsedSections.slabs}
208→            onToggle={() => toggleSection('slabs')}
209→          >
210→            {(floor.slabs || []).map(slab => (
211→              <div
212→                key={slab.id}
213→                className={`${styles.item} ${selectedId === slab.id ? styles.itemSelected : ''}`}
214→                onClick={() => selectObject(slab.id, 'slab')}
215→              >
216→                {getSlabDisplayLabel(slab)}
217→              </div>
218→            ))}
219→          </Section>
220→
221→          <Section
222→            title="Walls"
223→            count={floor.walls.length}
224→            collapsed={collapsedSections.walls}
225→            onToggle={() => toggleSection('walls')}
226→          >
227→            {floor.walls.map(w => (
228→              <div
229→                key={w.id}
230→                className={`${styles.item} ${selectedId === w.id ? styles.itemSelected : ''}`}
231→                onClick={() => selectObject(w.id, 'wall')}
232→              >
233→                Wall {w.id.split('_').pop()}
234→              </div>
235→            ))}
236→          </Section>
237→
238→          <Section
239→            title="Annotations"
240→            count={(floor.annotations || []).length}
241→            collapsed={collapsedSections.annotations}
242→            onToggle={() => toggleSection('annotations')}
243→          >
244→            {(floor.annotations || []).map((annotation) => (
245→              <div
246→                key={annotation.id}
247→                className={`${styles.item} ${selectedId === annotation.id ? styles.itemSelected : ''}`}
248→                onClick={() => selectObject(annotation.id, 'annotation')}
249→              >
250→                {getAnnotationDisplayLabel(annotation)}
251→              </div>
252→            ))}
253→          </Section>
254→
255→          <Section
256→            title="Beams"
257→            count={(floor.beams || []).length}
258→            collapsed={collapsedSections.beams}
259→            onToggle={() => toggleSection('beams')}
260→          >
261→            {(floor.beams || []).map(beam => (
262→              <div
263→                key={beam.id}
264→                className={`${styles.item} ${selectedId === beam.id ? styles.itemSelected : ''}`}
265→                onClick={() => selectObject(beam.id, 'beam')}
266→              >
267→                {getBeamDisplayLabel(beam, floor.columns || [])}
268→              </div>
269→            ))}
270→          </Section>
271→
272→          <Section
273→            title="Stairs"
274→            count={(floor.stairs || []).length}
275→            collapsed={collapsedSections.stairs}
276→            onToggle={() => toggleSection('stairs')}
277→          >
278→            {(floor.stairs || []).map(stair => (
279→              <div
280→                key={stair.id}
281→                className={`${styles.item} ${selectedId === stair.id ? styles.itemSelected : ''}`}
282→                onClick={() => selectObject(stair.id, 'stair')}
283→              >
284→                {getStairDisplayLabel(stair)}
285→              </div>
286→            ))}
287→          </Section>
288→
289→          <Section
290→            title="Landings"
291→            count={(floor.landings || []).length}
292→            collapsed={collapsedSections.landings}
293→            onToggle={() => toggleSection('landings')}
294→          >
295→            {(floor.landings || []).map(landing => (
296→              <div
297→                key={landing.id}
298→                className={`${styles.item} ${selectedId === landing.id ? styles.itemSelected : ''}`}
299→                onClick={() => selectObject(landing.id, 'landing')}
300→              >
301→                {getLandingDisplayLabel(landing)}
302→              </div>
303→            ))}
304→          </Section>
305→
306→          <Section
307→            title="Doors"
308→            count={floor.doors.length}
309→            collapsed={collapsedSections.doors}
310→            onToggle={() => toggleSection('doors')}
311→          >
312→            {floor.doors.map(d => (
313→              <div
314→                key={d.id}
315→                className={`${styles.item} ${selectedId === d.id ? styles.itemSelected : ''}`}
316→                onClick={() => selectObject(d.id, 'door')}
317→              >
318→                Door {d.id.split('_').pop()}
319→              </div>
320→            ))}
321→          </Section>
322→
323→          <Section
324→            title="Windows"
325→            count={floor.windows.length}
326→            collapsed={collapsedSections.windows}
327→            onToggle={() => toggleSection('windows')}
328→          >
329→            {floor.windows.map(w => (
330→              <div
331→                key={w.id}
332→                className={`${styles.item} ${selectedId === w.id ? styles.itemSelected : ''}`}
333→                onClick={() => selectObject(w.id, 'window')}
334→              >
335→                Window {w.id.split('_').pop()}
336→              </div>
337→            ))}
338→          </Section>
339→
340→          <Section
341→            title="Columns"
342→            count={(floor.columns || []).length}
343→            collapsed={collapsedSections.columns}
344→            onToggle={() => toggleSection('columns')}
345→          >
346→            {(floor.columns || []).map(column => (
347→              <div
348→                key={column.id}
349→                className={`${styles.item} ${selectedId === column.id ? styles.itemSelected : ''}`}
350→                onClick={() => selectObject(column.id, 'column')}
351→              >
352→                {getColumnListLabel(column, floor.columns || [])}
353→              </div>
354→            ))}
355→          </Section>
356→
357→          <Section
358→            title="Rooms"
359→            count={floor.rooms.length}
360→            collapsed={collapsedSections.rooms}
361→            onToggle={() => toggleSection('rooms')}
362→          >
363→            {floor.rooms.map(r => (
364→              <div
365→                key={r.id}
366→                className={`${styles.item} ${selectedId === r.id ? styles.itemSelected : ''}`}
367→                onClick={() => selectObject(r.id, 'room')}
368→              >
369→                {r.name}
370→              </div>
371→            ))}
372→          </Section>
373→        </>
374→      )}
375→    </div>
376→  );
377→}
