 3→export default function Modal({ title, onClose, children }) {
 4→  const overlayRef = useRef(null);
 5→
 6→  useEffect(() => {
 7→    const handleKey = (e) => {
 8→      if (e.key === 'Escape') onClose();
 9→    };
10→    window.addEventListener('keydown', handleKey);
11→    return () => window.removeEventListener('keydown', handleKey);
12→  }, [onClose]);
13→
14→  const handleOverlayClick = (e) => {
15→    if (e.target === overlayRef.current) onClose();
16→  };
17→
18→  return (
19→    <div
20→      ref={overlayRef}
21→      onClick={handleOverlayClick}
22→      style={{
23→        position: 'fixed',
24→        inset: 0,
25→        background: 'rgba(10, 12, 15, 0.45)',
26→        backdropFilter: 'blur(4px)',
27→        display: 'flex',
28→        alignItems: 'center',
29→        justifyContent: 'center',
30→        zIndex: 1000,
31→        animation: 'modalOverlayIn 0.2s ease',
32→      }}
33→    >
34→      <div style={{
