1264→      </div>
1265→      {workspaceMode === 'sheet' && sheet && (
1266→        <SheetExportMenu sheet={sheet} editorDispatch={editorDispatch} />
1267→      )}
1268→      {content}
1269→      {selectedId && selectedType !== 'floor' && (
